import{_ as t,o as n,c as i,a2 as a}from"./chunks/framework.BWuWLRhz.js";const m=JSON.parse('{"title":"Epic: Monetization","description":"","frontmatter":{},"headers":[],"relativePath":"epics/monetization.md","filePath":"epics/monetization.md"}'),o={name:"epics/monetization.md"};function r(s,e,l,c,d,u){return n(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="epic-monetization" tabindex="-1">Epic: Monetization <a class="header-anchor" href="#epic-monetization" aria-label="Permalink to &quot;Epic: Monetization&quot;">​</a></h1><blockquote><p>A plugin billing model based on manifest-declared pricing tiers and author-signed Ed25519 entitlement tokens — no platform payment processor lock-in.</p></blockquote><h2 id="status" tabindex="-1">Status <a class="header-anchor" href="#status" aria-label="Permalink to &quot;Status&quot;">​</a></h2><p>⏳ In Progress</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Phase 1 (complete) lets plugin authors monetize via a manifest <code>monetization</code> object and offline-verifiable entitlement tokens signed with the author&#39;s Ed25519 key. The runtime gates paywalled routes by <code>routePrefix</code>. The Account plugin handles purchase and license import; Console handles entitlement oversight and manual payment confirmation. Phase 2 (post-v1) adds a <code>sdk.billing.grantEntitlement()</code> seam so plugins can accept Stripe/PayPal webhooks and automate the grant flow without a platform payment adapter.</p><h2 id="tasks" tabindex="-1">Tasks <a class="header-anchor" href="#tasks" aria-label="Permalink to &quot;Tasks&quot;">​</a></h2><h4 id="✅-7-1-—-plugin-monetization-rfc-0003" tabindex="-1">✅ 7.1 — Plugin monetization (RFC 0003) <a class="header-anchor" href="#✅-7-1-—-plugin-monetization-rfc-0003" aria-label="Permalink to &quot;✅ 7.1 — Plugin monetization (RFC 0003)&quot;">​</a></h4><p><strong>Goal:</strong> Let plugin authors monetize plugins via a manifest-declared model + author-signed entitlement gating. RFC 0003 accepted.</p><p><strong>Deliverables:</strong></p><ul><li>Manifest <code>monetization</code> object (<code>model</code>/<code>interval</code>/<code>tiers</code>/<code>license.publicKey</code>); validation + tests; <code>@sovereignfs/manifest</code> minor bump</li><li>Reserved <code>sdk.billing</code>/<code>entitlements</code> surface (stub throwing <code>NotImplementedError</code>) + <code>EntitlementRequiredError</code>; <code>@sovereignfs/sdk</code> minor bump</li><li>Entitlement gating in runtime middleware by <code>routePrefix</code> (paywall / <code>402</code>), mirroring the disabled-plugin pattern; <code>entitlements</code> table with <code>tenant_id</code></li><li><code>PaymentProvider</code> adapter interface; manual/bank, Stripe, and PayPal adapters (hosted checkout + webhooks); offline signature verification against author public key</li><li>Subscription management in Account (purchase/import license, active subscriptions, renewal/cancel); entitlement oversight + manual-payment confirmation in Console</li><li>Paywall page (runtime-owned); plugin key-rotation support; docs</li></ul><p><strong>Dependencies:</strong> Task 0.5.08 (API namespace — webhook endpoints), Task 0.5.05 (<code>sdk.db</code>)</p><p><strong>SRS reference:</strong> RFC 0003</p><p><strong>Review checklist:</strong></p><ul><li>A <code>recurring</code> plugin is paywalled without an entitlement; a signed license grants access; a Stripe webhook renews the entitlement; manual import works with no gateway</li></ul><hr><h4 id="📋-7-2-—-phase-2-payment-integration-rfc-0003-phase-2" tabindex="-1">📋 7.2 — Phase 2 payment integration (RFC 0003 Phase 2) <a class="header-anchor" href="#📋-7-2-—-phase-2-payment-integration-rfc-0003-phase-2" aria-label="Permalink to &quot;📋 7.2 — Phase 2 payment integration (RFC 0003 Phase 2)&quot;">​</a></h4><p><strong>Goal:</strong> Automate the payment → entitlement flow that Phase 1 (Task 0.8.01) leaves manual. Three sub-tracks, independently deliverable:</p><p><strong>Sub-track A — Bank transfer + admin confirmation</strong></p><ul><li>New <code>payment_requests</code> table (both dialects; drizzle-kit migration).</li><li>Console <strong>Pending Payments</strong> sub-section under Entitlements — lists pending requests with subscriber, plugin, tier, amount, and requested-at.</li><li>Admin <strong>Confirm</strong> / <strong>Reject</strong> actions: confirm auto-creates an entitlement row (<code>source: &#39;bank_transfer&#39;</code>); reject optionally sends a notification email.</li><li><code>sdk.billing.requestSubscription({ pluginId, tierId })</code> (currently <code>NotImplementedError</code> stub → implemented) creates the request row and returns configured bank details.</li><li>Console Settings gains a <code>bank_transfer_details</code> field (IBAN / instructions).</li></ul><p><strong>Sub-track B — Stripe webhook</strong></p><ul><li>No platform adapter code — integration lives in the plugin.</li><li><code>sdk.billing.grantEntitlement({ userId, pluginId, tierId, expiresAt })</code> (new) lets a plugin&#39;s webhook handler write an entitlement server-side without a signed token.</li><li>Example Stripe webhook handler in <code>plugins/example-monetized/</code> or docs.</li></ul><p><strong>Sub-track C — PayPal webhook</strong></p><ul><li>Same pattern as Stripe; same <code>sdk.billing.grantEntitlement()</code> seam.</li></ul><p><strong>Dependencies:</strong> Task 0.8.01 (Phase 1 must be in production), Task 1.0.01 (encryption at rest — payment request records contain PII)</p><p><strong>SRS reference:</strong> RFC 0003 Phase 2</p><p><strong>Review checklist:</strong></p><ul><li>Bank transfer: user submits request → Console &quot;Pending Payments&quot; shows it → admin confirms → user&#39;s next request passes the paywall without re-importing a token</li><li>Bank transfer: admin rejects → user receives notification email (when SMTP configured)</li><li>Stripe: plugin webhook verifies signature, calls <code>sdk.billing.grantEntitlement()</code>, user gains access</li><li><code>sdk.billing.requestSubscription()</code> throws <code>EntitlementRequiredError</code> when called from a non-plugin context</li></ul><hr><h2 id="related-rfcs" tabindex="-1">Related RFCs <a class="header-anchor" href="#related-rfcs" aria-label="Permalink to &quot;Related RFCs&quot;">​</a></h2><ul><li><a href="./../rfcs/0003-plugin-monetization.html">RFC 0003 — Plugin monetization</a></li></ul><h2 id="related-docs" tabindex="-1">Related Docs <a class="header-anchor" href="#related-docs" aria-label="Permalink to &quot;Related Docs&quot;">​</a></h2><ul><li><a href="./../plugin-development.html">plugin-development.md — manifest <code>monetization</code> field</a></li></ul><h2 id="cross-references" tabindex="-1">Cross-references <a class="header-anchor" href="#cross-references" aria-label="Permalink to &quot;Cross-references&quot;">​</a></h2><ul><li>Entitlement gating in the runtime middleware is part of <a href="./platform-shell.html">Platform Shell</a>.</li><li>The Account plugin&#39;s subscription management UI is part of <a href="./plugin-accounts.html">Plugin — Accounts</a>.</li><li>The Console entitlement oversight and payment confirmation UI is part of <a href="./plugin-console.html">Plugin — Console</a>.</li></ul>',35)])])}const h=t(o,[["render",r]]);export{m as __pageData,h as default};
